import React from 'react'
import {useState} from 'react';

function App() {
  const [data, inputData] = useState({text:"", status:false});
  const [tasks, addTasks] = useState([]);

  const handleChange = (e)=>
  {
    inputData({...data,text:e.target.value,status:false})

  }

  function addTask()
  {
    addTasks([...tasks,data]);
  }

  const changeStatus = (index)=>
  {
    let newArr = [...tasks];
    newArr[index].status = !newArr[index].status;
    addTasks(newArr);

  }

  return (
    <>
    <input type="text" name="text" placeholder="Enter your task..." onChange={handleChange} />
    <br />
    <button onClick={addTask}>ADD</button>
    <br />
    <ul>
      {tasks.map((task,i)=>
      {
        return (
          <li key={i}>
            <p>{task.text}</p>
            <span>{task.status? "Completed" : "Pending"}</span>
            <br />
            <button onClick={()=>changeStatus(i)}>Toggle status</button>
          </li>
        )
      })}
    </ul>
    </>
  )
}

export default App;